#' Catch and Translate RTMB Errors into User-Friendly Messages
#'
#' @description
#' This internal helper function wraps an R expression in a [tryCatch()] block to
#' capture cryptic error messages generated by the RTMB automatic differentiation
#' engine or C++ backend, translating them into descriptive hints in Japanese.
#'
#' @details
#' It uses regular expressions to categorize common RTMB failure modes, such as:
#' \itemize{
#'   \item **Missing Objects/Functions**: Detects if a variable or a specific distribution
#'   function (e.g., `normal_lpdf`) is missing from the environment.
#'   \item **Index Errors**: Identifies subscript out of bounds errors.
#'   \item **AD Type Destruction**: Catches the "lost class attribute" error, often caused
#'   by incorrect initialization of vectors (e.g., using `numeric(N)` and partial assignment
#'   inside loops).
#'   \item **Matrix Dimension Mismatch**: Identifies non-conformable arguments in
#'   matrix multiplication.
#' }
#'
#' @param expr An R expression to be evaluated, typically representing the logic within
#' a specific model block.
#' @param block_name A character string identifying the context of the error
#' (e.g., "parameters", "model", "transform", or "generate").
#'
#' @return The result of evaluating the \code{expr}. If an error occurs, it throws
#' a formatted [stop()] message.
#'
#' @keywords internal
with_rtmb_error_handling <- function(expr, block_name) {
  tryCatch({
    expr
  }, error = function(e) {
    msg <- conditionMessage(e)
    call_expr <- conditionCall(e)

    call_str <- if (!is.null(call_expr)) {
      code_snippet <- paste(deparse(call_expr), collapse = " ")
      if (nchar(code_snippet) > 100) paste0(substr(code_snippet, 1, 97), "...") else code_snippet
    } else {
      "不明な箇所"
    }

    # 1. 存在しない変数の使用
    if (grepl("object '.*' not found", msg) || grepl("オブジェクト '.*' がありません", msg)) {
      var_name <- sub(".*(?:object|オブジェクト) '(.*)'.*", "\\1", msg)
      stop(sprintf("【%s ブロックのエラー】存在しない変数 '%s' が使われています。\n  [発生箇所]: %s\n  * data または parameters に含まれているか確認してください。",
                   block_name, var_name, call_str), call. = FALSE)
    }

    # 1. 存在しない関数の使用
    if (grepl("could not find function", msg) || grepl("関数 .* を見つけることができません", msg) || grepl("関数 .* が見つかりません", msg)) {
      func_name <- sub(".*(?:function|関数) [\"']?(.*?)[\"']? ?(?:を見つける|が見つかり|could not).*", "\\1", msg)
      stop(sprintf("【%s ブロックのエラー】存在しない関数 '%s' が使われています。\n  [発生箇所]: %s",
                   block_name, func_name, call_str), call. = FALSE)
    }

    # 2. インデックスエラー
    if (grepl("subscript out of bounds", msg) || grepl("範囲外", msg)) {
      stop(sprintf("【%s ブロックのエラー】配列や行列のインデックスが範囲外です。\n  [発生箇所]: %s",
                   block_name, call_str), call. = FALSE)
    }

    # 3. advector の破壊 / 型変換の失敗
    if (grepl("lost class attribute", msg) || grepl("Invalid argument to 'advector'", msg) ||
        grepl("数学関数に非数値引数", msg) || grepl("non-numeric argument to mathematical function", msg)) {
      stop(sprintf("【%s ブロックのエラー】自動微分(AD)の型が破壊されたか、不正な型の計算が行われました。\n  [発生箇所]: %s\n  * 原因例: numeric(N)等で初期化した空ベクトルへの代入 (型がリスト化してしまいます)。\n  * 対策:\n    1. 計算をベクトル化してループを避ける。\n    2. 'vec <- rep(theta[1]*0, N)' のようにAD型を保持したまま初期化する。\n    3. 'advector(numeric(N))' を使用する。",
                   block_name, call_str), call. = FALSE)
    }

    # 4. 行列の次元の不一致
    if (grepl("non-conformable arguments", msg) || grepl("適合しない", msg) || grepl("非等角", msg)) {
      stop(sprintf("【%s ブロックのエラー】行列の掛け算(%%*%%)や演算で次元が合っていません。\n  [発生箇所]: %s\n  * 注意: RTMBの行列演算では、R標準の「自動リサイクル規則（長さの違うベクトルの自動補完）」は適用されません。次元を厳密に合わせるか、rep()等で明示的にサイズを揃えてください。",
                   block_name, call_str), call. = FALSE)
    }

    # その他のエラー
    stop(sprintf("【%s ブロックのエラー】\n  [メッセージ]: %s\n  [発生箇所]: %s",
                 block_name, msg, call_str), call. = FALSE)
  })
}

#' 環境をリストに変換しつつ、元のリストの順序を保持する内部関数
#' @keywords internal
env_to_ordered_list <- function(env, orig_list, code_ast = NULL) {
  env_list <- as.list(env)
  orig_names <- names(orig_list)
  
  if (!is.null(code_ast)) {
    extract_assigned_vars <- function(expr) {
      vars <- character()
      if (is.call(expr)) {
        if (identical(expr[[1]], as.name("<-")) || identical(expr[[1]], as.name("="))) {
          if (is.name(expr[[2]])) vars <- c(vars, as.character(expr[[2]]))
        } else if (identical(expr[[1]], as.name("{"))) {
          for (i in 2:length(expr)) {
            vars <- c(vars, extract_assigned_vars(expr[[i]]))
          }
        }
      }
      return(unique(vars))
    }
    
    assigned_vars <- extract_assigned_vars(code_ast)
    assigned_vars <- intersect(assigned_vars, names(env_list))
    new_names <- intersect(assigned_vars, setdiff(names(env_list), orig_names))
    other_new_names <- setdiff(names(env_list), c(orig_names, new_names))
    new_names <- c(new_names, other_new_names)
  } else {
    new_names <- setdiff(names(env_list), orig_names)
  }
  
  return(env_list[c(intersect(orig_names, names(env_list)), new_names)])
}

#' RTMB_Model インスタンスを生成するラッパー関数
#'
#' @description
#' ユーザーが定義したデータ、およびモデルコード（尤度や事前分布）を結合し、
#' ベイズ推論（MCMC, VB, MAP推定）を実行するための `RTMB_Model` (R6クラス) インスタンスを生成します。
#'
#' @param data モデルで使用する観測データや定数（サンプルサイズなど）を含む名前付きリスト。
#' @param code `rtmb_code(...)` で記述されたモデル定義ブロック（data, parameters, model, transform, generate を含む）。
#' @param par_names 各パラメータの次元に対応する具体的な変数名のリスト（省略可能）。
#' @param init パラメータの初期値のリストまたは数値ベクトル（省略可能）。指定しない場合は自動でランダムに初期化されます。
#' @param view `summary()` などで結果を出力する際、優先して上部に表示したいパラメータ名の文字ベクトル（省略可能）。
#'
#' @return モデルのコンパイルと事前テストが完了した `RTMB_Model` クラスのインスタンス。
#' @export
rtmb_model <- function(data, code, par_names = list(), init = NULL, view = NULL) {

  if (!"parameters" %in% names(code)) stop("code の中に 'parameters = { ... }' ブロックが必要です。")
  if (!"model" %in% names(code)) stop("code の中に 'model = { ... }' ブロックが必要です。")

  for (name in names(data)) {
    if (is.data.frame(data[[name]])) {
      data[[name]] <- as.matrix(data[[name]])
      message(sprintf("【自動変換】データ '%s' を data.frame から matrix に変換しました。", name))
    }
  }

  # --- 1. Data ブロックの静的検証 (オプション) ---
  if ("data" %in% names(code)) {
    data_vars <- all.vars(code$data)
    missing_data <- setdiff(data_vars, names(data))
    if (length(missing_data) > 0) {
      stop(sprintf("【data ブロックの宣言エラー】\n宣言された変数 '%s' が、渡された data リスト(%s)の中に存在しません。",
                   missing_data[1], paste(names(data), collapse = ", ")), call. = FALSE)
    }
  }

  if ("setup" %in% names(code)) {
    # data を R の環境に展開し、その中で setup のコードを評価する
    dat_env <- list2env(data, parent = parent.frame())
    tryCatch({
      eval(code$setup, envir = dat_env)
    }, error = function(e) {
      stop(sprintf("【setup ブロックのエラー】データの前処理中にエラーが発生しました:\n  %s", conditionMessage(e)), call. = FALSE)
    })
    # 評価後に作成・変更された変数をすべて data リストに戻す
    #data <- as.list(dat_env)
    data <- env_to_ordered_list(dat_env, data, code$setup)
  }

  # --- 2. Parameters ブロックの静的検証と評価 ---
  param_exprs <- as.list(code$parameters)[-1]
  evaluated_par_list <- list()
  eval_env <- list2env(data, parent = parent.env(globalenv()))

  for (e in param_exprs) {
    if (is.null(e)) next
    if (is.call(e) && (identical(e[[1]], as.name("=")) || identical(e[[1]], as.name("<-")))) {
      v_name <- as.character(e[[2]])
      d_expr <- e[[3]]

      # ★ Rのスコープに頼らない最強のAST静的解析 ★
      # all.vars は関数名(Dimなど)を除外し、使われている純粋な変数名だけを抽出します
      used_vars <- all.vars(d_expr)
      missing_vars <- setdiff(used_vars, names(data))

      if (length(missing_vars) > 0) {
        stop(sprintf("【parameters ブロックのエラー】\n存在しない変数 '%s' が使われています。\n  [発生箇所]: %s\n  * data リストに含まれているか確認してください。",
                     missing_vars[1], paste(deparse(e), collapse = " ")), call. = FALSE)
      }

      # チェックを通過したものだけを安全に評価
      evaluated_par_list[[v_name]] <- eval(d_expr, envir = eval_env)
    } else {
      stop("parametersブロックの書式エラー: ", paste(deparse(e), collapse = " "))
    }
  }

  for (v_name in names(evaluated_par_list)) {
    p <- evaluated_par_list[[v_name]]
    if (!is.null(p$type) && p$type %in% c("CF_cov", "CF_corr")) {
      if (length(p$dim) != 2 || p$dim[1] != p$dim[2]) {
        stop(sprintf("【パラメータ定義エラー】変数 '%s' に type = '%s' が指定されていますが、正方行列の次元ではありません (指定された次元: %s)。",
                     v_name, p$type, paste(p$dim, collapse = " x ")), call. = FALSE)
      }
    }
  }

  check_unsupported_funcs <- function(expr) {
    if (is.call(expr)) {
      func_name <- as.character(expr[[1]])
      # 関数名が長さ1の文字列である場合のみ判定
      if (length(func_name) == 1 && func_name %in% c("ifelse", "apply", "sapply", "lapply", "tapply", "vapply")) {
        stop(sprintf("【model ブロックの記述エラー】自動微分(AD)に対応していない関数 '%s' が使用されています。\n  * 対策 (条件分岐): '(条件) * A + (!条件) * B' のような四則演算で代替してください。\n  * 対策 (ループ関数): 通常の for ループに書き換えてください。", func_name), call. = FALSE)
      }
      # 再帰的に内部をチェック
      lapply(as.list(expr)[-1], check_unsupported_funcs)
    }
  }
  if ("model" %in% names(code)) {
    check_unsupported_funcs(code$model)
  }

  # --- 3. 動的コンパイル (model, transform, generate) ---
  user_env <- if (!is.null(code$env)) code$env else parent.frame()

  comp_model <- eval(bquote(model_code(.(code$model), env = user_env)))

  comp_transform <- NULL
  if ("transform" %in% names(code)) {
    comp_transform <- eval(bquote(transform_code(.(code$transform), env = user_env)))
  }

  comp_generate <- NULL
  if ("generate" %in% names(code)) {
    comp_generate <- eval(bquote(transform_code(.(code$generate), env = user_env)))
  }

  # --- 4. 事前テスト (Sandbox実行) ---
  cat("Pre-checking model code...\n")
  set.seed(12345)

  test_unc_list <- lapply(evaluated_par_list, function(p) {
    rnorm(p$unc_length, mean = 0, sd = 0.1)
  })
  test_para <- to_constrained(test_unc_list, evaluated_par_list)

  for (name in names(evaluated_par_list)) {
    p <- evaluated_par_list[[name]]
    if (!is.null(p$init)) {
      val <- rep(p$init, length.out = p$length)
      if (any(is.na(val))) {
        val[is.na(val)] <- as.numeric(test_para[[name]])[is.na(val)]
      }
      test_para[[name]] <- array(val, dim = p$dim)
    }
  }

  if (!is.null(comp_transform)) {
    test_tran <- BayesRTMB:::with_rtmb_error_handling({ comp_transform(data, test_para) }, "transform")
    if (is.list(test_tran)) test_para <- c(test_para, test_tran)
  }

  BayesRTMB:::with_rtmb_error_handling({ comp_model(data, test_para) }, "model")

  if (!is.null(comp_generate)) {
    BayesRTMB:::with_rtmb_error_handling({ comp_generate(data, test_para) }, "generate")
  }

  # --- 5. 実行用安全ラッパーの作成 ---
  safe_model <- function(dat, para) { BayesRTMB:::with_rtmb_error_handling({ comp_model(dat, para) }, "model") }

  safe_transformed <- NULL
  if (!is.null(comp_transform)) {
    safe_transformed <- function(dat, para) {
      res <- BayesRTMB:::with_rtmb_error_handling({ comp_transform(dat, para) }, "transform")
      if (!is.list(res)) stop("戻り値は「名前付きリスト (list)」である必要があります。")
      res
    }
    attr(safe_transformed, "raw_expr") <- code$transform
  }

  safe_generate <- NULL
  if (!is.null(comp_generate)) {
    safe_generate <- function(dat, para) {
      res <- BayesRTMB:::with_rtmb_error_handling({ comp_generate(dat, para) }, "generate")
      if (!is.list(res)) stop("戻り値は「名前付きリスト (list)」である必要があります。")
      res
    }
    attr(safe_generate, "raw_expr") <- code$generate
  }

  # --- 6. R6クラスへ渡す ---
  obj <- RTMB_Model$new(
    data       = data,
    par_list   = evaluated_par_list,
    log_prob   = safe_model,
    transform  = safe_transformed,
    generate   = safe_generate,
    par_names  = par_names,
    init       = init,
    view       = view,
    code       = code
  )

  return(obj)
}

#' ユーザーのコード(AST)を探索し、パッケージの関数に名前空間を自動付与する関数
#' @param expr 評価前のコード(AST)
#' @param pkg 対象のパッケージ名
#' @keywords internal
inject_namespace <- function(expr, pkg = "BayesRTMB") {
  # 単一の変数名や定数なら何もしない
  if (is.atomic(expr) || is.name(expr)) {
    return(expr)
  }

  # 関数呼び出し、演算子、ブロック ({...}, for, if など) の場合
  if (is.call(expr)) {
    # すでに pkg::func() のように名前空間が指定されている場合はスキップ
    if (identical(expr[[1]], quote(`::`)) || identical(expr[[1]], quote(`:::`))) {
      return(expr)
    }

    # 呼び出されている関数名を取得
    func_name <- as.character(expr[[1]])

    # func_name が単一の文字列である場合のみ処理 (クロージャの直接呼び出し等を回避)
    if (length(func_name) == 1) {
      # その関数が BayesRTMB パッケージの namespace 内に存在するかチェック
      # inherits = FALSE にすることで、base や stats の関数 (sum, log 等) を除外
      if (exists(func_name, envir = asNamespace(pkg), inherits = FALSE)) {
        # 存在すれば、 BayesRTMB::func_name にすり替える
        expr[[1]] <- call("::", as.name(pkg), as.name(func_name))
      }
    }

    # 関数の中身（引数や、for/if の中身）に対しても再帰的に適用する
    for (i in 2:length(expr)) {
      # 修正箇所: ASTにおける「空の引数」を正しく判定する
      if (!identical(expr[[i]], quote(expr=))) {
        expr[[i]] <- inject_namespace(expr[[i]], pkg)
      }
    }
  }

  return(expr)
}

#' StanライクなRTMBモデル定義ブロック (ハイブリッド対応版)
#'
#' @description
#' R標準のカンマ区切り記法と、Stan風のカンマなし記法({}の内側での記述)の両方に対応します。
#'
#' @param ... モデル定義ブロック
#' @return 未評価のコードブロックのリスト
#' @export
rtmb_code <- function(...) {
  args <- as.list(match.call())[-1]
  code_list <- list()
  valid_blocks <- c("setup", "data", "parameters", "transform", "model", "generate")

  # パターン1: 前者の書き方 (名前付き引数・カンマ区切り)
  if (!is.null(names(args))) {
    for (name in names(args)) {
      if (name == "") next
      if (name %in% valid_blocks) {
        code_list[[name]] <- args[[name]]
      } else {
        stop(sprintf("未知のブロック '%s' が指定されています。有効なブロックは %s です。",
                     name, paste(valid_blocks, collapse = ", ")), call. = FALSE)
      }
    }

  } else if (length(args) == 1 && is.null(names(args))) {
    # パターン2: 後者の書き方 (Stan風・カンマなし・全体を{}で囲む)
    ast <- args[[1]]
    if (is.call(ast) && identical(ast[[1]], as.name("{"))) {
      exprs <- as.list(ast)[-1]

      for (e in exprs) {
        if (is.null(e)) next

        if (is.call(e)) {
          block_name <- as.character(e[[1]])
          if (block_name %in% valid_blocks) {
            code_list[[block_name]] <- if (length(e) >= 2) e[[2]] else quote({})
          } else {
            stop(sprintf("未知のブロック '%s' が指定されています。有効なブロックは %s です。",
                         block_name, paste(valid_blocks, collapse = ", ")), call. = FALSE)
          }
        } else {
          stop(sprintf("rtmb_code内の記述が不正です: '%s'",
                       paste(deparse(e), collapse = " ")), call. = FALSE)
        }
      }
    } else {
      stop("rtmb_code() の記述形式が不正です。カンマで区切るか、全体を {} で囲んで記述してください。", call. = FALSE)
    }
  } else {
    stop("rtmb_code() の記述形式が不正です。カンマで区切るか、全体を {} で囲んで記述してください。", call. = FALSE)
  }

  code_list$env <- parent.frame()
  # rtmb_code の段階では名前空間の注入を行わず、そのままASTを返す
  return(code_list)
}


#' Model Code Wrapper for RTMB
#'
#' @param expr A block of code containing model description.
#' @param env Environment to assign to the generated function.
#' @return A standard R function object taking (dat, par).
#' @export
model_code <- function(expr, env = parent.frame()) {
  raw_expr <- substitute(expr)

  if (is.name(raw_expr)) {
    evaluated <- eval(raw_expr, envir = env)
    if (is.language(evaluated)) {
      raw_expr <- evaluated
    }
  }

  # --- ここで通常の数学関数等に名前空間を注入 ---
  raw_expr <- inject_namespace(raw_expr, pkg = "BayesRTMB")

  # 式を再帰的に走査し、`~` の記述を書き換える
  rewrite_formula <- function(x) {
    if (is.call(x)) {
      if (identical(x[[1]], as.name("~"))) {
        target <- x[[2]]
        dist_call <- x[[3]]

        if (!is.call(dist_call)) {
          stop(sprintf("The right side of '~' must be a distribution function call. (e.g., %s( ... ))",
                       as.character(dist_call)), call. = FALSE)
        }

        dist_name <- as.character(dist_call[[1]])
        dist_args <- as.list(dist_call[-1])

        name_lpdf <- paste0(dist_name, "_lpdf")
        name_lpmf <- paste0(dist_name, "_lpmf")

        exists_in_pkg <- function(fname) {
          requireNamespace("BayesRTMB", quietly = TRUE) &&
            exists(fname, mode = "function", envir = asNamespace("BayesRTMB"), inherits = FALSE)
        }

        use_pkg_namespace <- FALSE

        if (exists_in_pkg(name_lpdf)) {
          actual_name <- name_lpdf
          use_pkg_namespace <- TRUE
        } else if (exists_in_pkg(name_lpmf)) {
          actual_name <- name_lpmf
          use_pkg_namespace <- TRUE
        } else if (exists(name_lpdf, mode = "function", envir = env)) {
          actual_name <- name_lpdf
        } else if (exists(name_lpmf, mode = "function", envir = env)) {
          actual_name <- name_lpmf
        } else {
          actual_name <- name_lpdf # デフォルト
        }

        if (use_pkg_namespace) {
          func_call <- call("::", as.name("BayesRTMB"), as.name(actual_name))
        } else {
          func_call <- as.name(actual_name)
        }

        new_call <- as.call(c(
          as.name("<-"),
          as.name("lp"),
          as.call(c(
            as.name("+"),
            as.name("lp"),
            as.call(c(func_call, target, dist_args))
          ))
        ))
        return(new_call)
      }
      x[] <- lapply(x, rewrite_formula)
    }
    return(x)
  }

  processed_expr <- rewrite_formula(raw_expr)

  if (is.call(processed_expr) && identical(processed_expr[[1]], as.name("{"))) {
    expr_elements <- as.list(processed_expr)[-1]
  } else {
    expr_elements <- list(processed_expr)
  }

  body_list <- c(
    list(as.name("{")),
    quote(RTMB::getAll(dat, par)),
    quote(lp <- 0),
    unname(expr_elements),
    quote(return(lp))
  )
  body_expr <- as.call(body_list)

  args <- as.pairlist(alist(dat = , par = ))
  fn_expr <- call("function", args, body_expr)

  log_prob_fn <- eval(fn_expr, envir = env)
  attr(log_prob_fn, "raw_expr") <- raw_expr

  return(log_prob_fn)
}


#' Transformed Code Wrapper for RTMB
#'
#' @param expr A block of code containing calculations for transformed parameters.
#' @param env Environment to assign to the generated function.
#' @return A function taking (dat, par) that returns a named list.
#' @export
transform_code <- function(expr, env = parent.frame()) {
  raw_expr <- substitute(expr)

  # --- ここで通常の数学関数等に名前空間を注入 ---
  raw_expr <- inject_namespace(raw_expr, pkg = "BayesRTMB")

  # 1. 中括弧 {} の中身をフラットにする
  if (is.call(raw_expr) && identical(raw_expr[[1]], as.name("{"))) {
    expr_elements <- as.list(raw_expr)[-1]
  } else {
    expr_elements <- list(raw_expr)
  }

  # 2. 最後の要素が出力として明示されているか判定
  last_elem <- expr_elements[[length(expr_elements)]]

  is_explicit_return <- FALSE
  if (is.call(last_elem)) {
    if (identical(last_elem[[1]], as.name("list"))) {
      is_explicit_return <- TRUE
      ret_call <- last_elem
    } else if (identical(last_elem[[1]], as.name("return"))) {
      is_explicit_return <- TRUE
      ret_call <- last_elem[[2]]
    }
  } else if (is.name(last_elem)) {
    is_explicit_return <- TRUE
    ret_call <- last_elem
  }

  if (is_explicit_return) {
    expr_elements <- expr_elements[-length(expr_elements)]
  } else {
    find_assignments <- function(x) {
      if (is.call(x)) {
        if (identical(x[[1]], as.name("<-")) || identical(x[[1]], as.name("="))) {
          if (is.name(x[[2]])) return(as.character(x[[2]]))
        }
        return(unique(unlist(lapply(as.list(x), find_assignments))))
      }
      return(NULL)
    }
    defined_vars <- find_assignments(raw_expr)
    ret_list_args <- lapply(defined_vars, as.name)
    names(ret_list_args) <- defined_vars
    ret_call <- as.call(c(list(as.name("list")), ret_list_args))
  }

  # 3. 関数ボディの構築
  body_list <- c(
    list(as.name("{")),
    quote(RTMB::getAll(dat, par)),
    unname(expr_elements),
    list(as.call(list(as.name("return"), ret_call)))
  )
  body_expr <- as.call(body_list)

  # 4. 関数オブジェクトの生成
  args <- as.pairlist(alist(dat = , par = ))
  fn_expr <- call("function", args, body_expr)
  fn <- eval(fn_expr, envir = env)
  attr(fn, "raw_expr") <- raw_expr

  return(fn)
}

#' パラメータ定義用コードブロック
#'
#' @description
#' `rtmb_model` に渡すパラメータのリストを定義します。
#' `{}` で囲まれたブロック内で `変数名 = Dim(...)` の形式で記述することで、
#' 評価を遅延させ、モデル構築時の厳密なエラーチェックを可能にします。
#'
#' @param expr `{}` で囲まれたパラメータ定義の式
#' @return 評価が遅延されたパラメータのリスト
#' @export
parameters_code <- function(expr) {
  # ブロック内のコードを評価せず、式(AST)としてキャプチャ
  ast <- substitute(expr)

  # `{` で囲まれたブロックであるかをチェック
  if (!is.call(ast) || !identical(ast[[1]], as.name("{"))) {
    stop("parameters_code は {} で囲まれたブロックを受け取る必要があります。\n例: parameters_code({ beta = Dim(K) })", call. = FALSE)
  }

  exprs <- as.list(ast)[-1] # 先頭の `{` を除外
  param_list <- list()

  for (e in exprs) {
    # 空行はスキップ
    if (is.null(e)) next

    # 代入演算子 (= または <-) を使っているかをチェック
    if (is.call(e) && (identical(e[[1]], as.name("=")) || identical(e[[1]], as.name("<-")))) {
      var_name <- as.character(e[[2]])
      param_list[[var_name]] <- e[[3]] # 右辺の式 (Dim(...)など) をそのまま保存
    } else {
      stop(sprintf("parameters_code内の記述が不正です: '%s'\n「変数名 = Dim(...)」の形式で記述してください。",
                   paste(deparse(e), collapse = " ")), call. = FALSE)
    }
  }

  return(param_list)
}

#' Transformed Code Wrapper for RTMB
#'
#' @param expr A block of code containing calculations for transformed parameters.
#' @param env Environment to assign to the generated function.
#' @return A function taking (dat, par) that returns a named list.
#' @export
transform_code <- function(expr, env = parent.frame()) {
  raw_expr <- substitute(expr)

  # --- ここで通常の数学関数等に名前空間を注入 ---
  raw_expr <- inject_namespace(raw_expr, pkg = "BayesRTMB")

  # 1. 中括弧 {} の中身をフラットにする
  if (is.call(raw_expr) && identical(raw_expr[[1]], as.name("{"))) {
    expr_elements <- as.list(raw_expr)[-1]
  } else {
    expr_elements <- list(raw_expr)
  }

  # 2. 最後の要素が出力として明示されているか判定
  last_elem <- expr_elements[[length(expr_elements)]]

  is_explicit_return <- FALSE
  if (is.call(last_elem)) {
    if (identical(last_elem[[1]], as.name("list"))) {
      is_explicit_return <- TRUE
      ret_call <- last_elem
    } else if (identical(last_elem[[1]], as.name("return"))) {
      is_explicit_return <- TRUE
      ret_call <- last_elem[[2]]
    }
  } else if (is.name(last_elem)) {
    is_explicit_return <- TRUE
    ret_call <- last_elem
  }

  if (is_explicit_return) {
    expr_elements <- expr_elements[-length(expr_elements)]
  } else {
    find_assignments <- function(x) {
      if (is.call(x)) {
        if (identical(x[[1]], as.name("<-")) || identical(x[[1]], as.name("="))) {
          if (is.name(x[[2]])) return(as.character(x[[2]]))
        }
        return(unique(unlist(lapply(as.list(x), find_assignments))))
      }
      return(NULL)
    }
    defined_vars <- find_assignments(raw_expr)
    ret_list_args <- lapply(defined_vars, as.name)
    names(ret_list_args) <- defined_vars
    ret_call <- as.call(c(list(as.name("list")), ret_list_args))
  }

  # 3. 関数ボディの構築
  body_list <- c(
    list(as.name("{")),
    quote(RTMB::getAll(dat, par)),
    unname(expr_elements),
    list(as.call(list(as.name("return"), ret_call)))
  )
  body_expr <- as.call(body_list)

  # 4. 関数オブジェクトの生成
  args <- as.pairlist(alist(dat = , par = ))
  fn_expr <- call("function", args, body_expr)
  fn <- eval(fn_expr, envir = env)
  attr(fn, "raw_expr") <- raw_expr

  return(fn)
}
#' データとパラメータの事前検証
#'
#' @description
#' `rtmb_model` にデータを渡す前に、R特有のデータ型（data.frameなど）が混入していないか、
#' および欠損値の有無などをチェックし、エラーや警告を出力します。
#'
#' @param dat_list モデルに渡すデータのリスト（通常、行列や数値ベクトルを含む）。
#' @param par_list `Dim()` で定義されたパラメータのリスト。
#'
#' @return 検証に成功した場合は不可視の `NULL` を返します。問題がある場合は `stop()` で処理を中断、または `warning()` を発出します。
#'
#' @details
#' RTMBの自動微分エンジンは純粋な `matrix` や `numeric` を要求します。
#' ユーザーが誤って `data.frame` を渡した場合、計算グラフの構築時に不可解なエラーが発生するため、
#' この関数で事前に捕捉します。
validate_data <- function(dat_list, par_list) {
  # 1. データフレームの変換
  for (name in names(dat_list)) {
    if (is.data.frame(dat_list[[name]])) {
      dat_list[[name]] <- as.matrix(dat_list[[name]])
    }
  }

  # 2. NAのチェック (stopに変更)
  for (name in names(dat_list)) {
    if (any(is.na(dat_list[[name]]))) {
      stop(sprintf("【データエラー】データ '%s' に欠損値(NA)が含まれています。\n  * 対策: モデルに渡す前にNAを除外するか、欠損値を補完してください。\n  * ヒント: 欠損値を無視したい場合は、NAのインデックスを取得し、尤度計算のループから外す処理をデータ前処理で行う必要があります。", name), call. = FALSE)
    }
  }

  return(dat_list)
}


#' 安全なRTMBモデルの構築（エラーメッセージ翻訳付き）
#'
#' @description
#' `rtmb_model` をラップし、内部の `MakeADFun` 実行時に発生する C++/RTMB 由来の
#' 難解なエラーメッセージを、ユーザーが理解しやすい日本語のヒントに翻訳して出力します。
#'
#' @param data `validate_data` を通過したデータのリスト。
#' @param parameters `Dim()` で定義されたパラメータのリスト。
#' @param model `model_code({})` で定義された尤度や事前分布のコードブロック。
#' @param generate `transform_code({})` で定義された生成量のコードブロック（省略可能）。
#'
#' @return 正常にコンパイルが完了した場合は、`rtmb_model` オブジェクト（R6クラスのインスタンス）を返します。
#'
#' @export
safe_rtmb_model <- function(data, parameters, model, generate = NULL) {
  # 事前検証を実行
  data <- validate_data(data, parameters)

  tryCatch({
    # 実際のモデル構築処理
    obj <- rtmb_model(data, parameters, model, generate)
    return(obj)

  }, error = function(e) {
    err_msg <- conditionMessage(e)

    # ADクラス消失エラーの翻訳
    if (grepl("lost class attribute", err_msg) || grepl("Invalid argument to 'advector'", err_msg)) {
      stop(
        "【モデル構築エラー】自動微分(AD)の型が途中で消失しました。\n",
        "・原因: model_code 内で rep() や空の array() に対して for ループで逐次代入を行っている可能性があります。\n",
        "・対策: 行列のベクトル化計算を使用するか、初期化には numeric(M) などを利用してください。\n",
        "[元のエラー]: ", err_msg,
        call. = FALSE
      )
    }

    # 不正な演算エラーの翻訳
    if (grepl("illegal operation", err_msg) || grepl("not a valid 'advector'", err_msg)) {
      stop(
        "【モデル構築エラー】実行不可能な演算、または型の不整合が発生しました。\n",
        "・原因: 行列の掛け算(%*%)の左右で次元が合っていない、または Dim() の型指定 (CF_cov, lower_tri など) が実際の行列サイズと矛盾している可能性があります。\n",
        "[元のエラー]: ", err_msg,
        call. = FALSE
      )
    }

    # 数値/行列型エラーの翻訳
    if (grepl("requires numeric/complex matrix/vector", err_msg)) {
      stop(
        "【データ型エラー】数値ベクトルまたは行列が必要な箇所に、別の型が渡されています。\n",
        "・原因: 観測データやインデックスが data.frame や list になっていませんか？\n",
        "[元のエラー]: ", err_msg,
        call. = FALSE
      )
    }

    # 未知のエラーはそのまま出力
    stop("【予期せぬエラー】\n", err_msg, call. = FALSE)
  })
}


#' RTMB-based GLMM wrapper function
#'
#' @param formula lme4-style formula (e.g., Y ~ X + (1 | GID))
#' @param data Data frame
#' @param family Character string of the distribution family (e.g., "gaussian", "binomial", "poisson")
#' @param laplace Logical; whether to marginalize random effects using Laplace approximation
#' @param penalty Type of regularization for fixed effects: "none", "rhs" (Regularized Horseshoe), or "ssp" (Spike and Slab Prior). Default is "none".
#' @param y_range Theoretical minimum and maximum values of the response variable as a vector c(min, max). Specifying this automatically enables weakly informative priors.
#' @param use_weak_info Logical; whether to explicitly use weakly informative priors (requires y_range for continuous models).
#' @param prior List of hyperparameters for the default fixed priors.
#' @param weak_info_prior List of hyperparameters for the weakly informative priors and regularization.
#' @param init List of initial values (generated automatically based on glm if omitted)
#' @export
rtmb_glmer <- function(formula, data, family = "gaussian", laplace = FALSE,
                       penalty = c("none", "rhs", "ssp"),
                       y_range = NULL,
                       use_weak_info = FALSE,
                       prior = list(Intercept_sd = 10, b_sd = 10, sigma_rate = 5, sd_rate = 5, nu_rate = 0.1, cutpoint_sd = 2.5, shape_rate = 1.0, phi_rate = 1.0, lkj_eta = 1.0),
                       weak_info_prior = list(max_beta = 1, sd_ratio = 0.5, expected_vars = 3, slab_scale = 2.0, slab_df = 4.0, ssp_ratio = 0.25),
                       init = NULL) {

  regularization <- match.arg(penalty)
  if (!requireNamespace("lme4", quietly = TRUE)) stop("フォーミュラの解析に 'lme4' パッケージが必要です。")
  has_random <- !is.null(lme4::findbars(formula))

  default_prior <- eval(formals(rtmb_glmer)$prior)
  prior <- modifyList(default_prior, prior)
  default_weak_prior <- eval(formals(rtmb_glmer)$weak_info_prior)
  weak_info_prior <- modifyList(default_weak_prior, weak_info_prior)

  if (!is.null(y_range) || regularization %in% c("rhs", "ssp")) {
    use_weak_info <- TRUE
  }

  families_requiring_yrange <- c("gaussian", "lognormal", "student_t")
  is_continuous <- family %in% families_requiring_yrange

  if (use_weak_info && is_continuous && is.null(y_range)) {
    stop("family = '", family, "' で弱情報事前分布（または正則化）を使用する場合、y_range の指定が必須です。")
  }

  if (has_random) {
    parsed <- lme4::lFormula(formula, data = data, control = lme4::lmerControl(check.nobs.vs.nlev = "ignore", check.nobs.vs.nRE  = "ignore"))
    Y <- model.response(parsed$fr)
    X <- parsed$X
    reTrms <- parsed$reTrms

    if (length(reTrms$Ztlist) > 1) stop("現在、単一のグループ化変数のみに対応しています。")

    Zt <- as.matrix(reTrms$Ztlist[[1]])
    group_idx <- as.integer(reTrms$flist[[1]])
    offset <- model.offset(parsed$fr)
    ranef_names <- parsed$reTrms$cnms[[1]]
    ranef_names[ranef_names == "(Intercept)"] <- "Int"
  } else {
    mf <- model.frame(formula, data)
    Y <- model.response(mf)
    X <- model.matrix(formula, mf)
    offset <- model.offset(mf)
    Zt <- NULL
    group_idx <- NULL
    ranef_names <- NULL
  }

  has_intercept <- "(Intercept)" %in% colnames(X)
  if (family == "ordered") has_intercept <- FALSE
  if ("(Intercept)" %in% colnames(X)) {
    X <- X[, colnames(X) != "(Intercept)", drop = FALSE]
  }

  fixed_names <- colnames(X)
  K_tmp <- ncol(X)

  if (is.matrix(Y)) {
    if (ncol(Y) == 2 && family == "binomial") {
      trials <- as.numeric(Y[, 1] + Y[, 2])
      Y <- as.numeric(Y[, 1])
    } else if (ncol(Y) == 1) {
      Y <- as.numeric(Y[, 1])
      trials <- rep(1, length(Y))
    } else stop("応答変数の行列形式が不正です。")
  } else {
    trials <- rep(1, length(Y))
    if (is.factor(Y)) {
      Y <- if (family %in% c("bernoulli", "binomial")) as.numeric(Y) - 1 else as.numeric(Y)
    } else Y <- as.numeric(Y)
  }

  # --- SSP時の初期値自動生成 ---
  if (regularization == "ssp" && is.null(init) && K_tmp > 0) {
    rhs_mod <- NULL
    suppressMessages(capture.output({
      rhs_mod <- rtmb_glmer(formula, data, family, laplace, penalty = "rhs", y_range = y_range, use_weak_info = use_weak_info, prior = prior, weak_info_prior = weak_info_prior, init = NULL)
    }))

    jac_target <- if (laplace) "random" else "none"

    ad_setup <- NULL
    suppressMessages(capture.output({
      ad_setup <- rhs_mod$build_ad_obj(laplace = laplace, jacobian_target = jac_target)
    }))

    ad_obj <- ad_setup$ad_obj
    best_obj <- Inf
    best_par <- ad_obj$par

    for (i in 1:4) {
      start_par <- if (i == 1) ad_obj$par else ad_obj$par + rnorm(length(ad_obj$par), 0, 0.5)
      opt <- suppressWarnings(try(nlminb(start = start_par, objective = ad_obj$fn, gradient = ad_obj$gr), silent = TRUE))
      if (!inherits(opt, "try-error") && !is.na(opt$objective) && opt$objective < best_obj) {
        best_obj <- opt$objective
        best_par <- opt$par
      }
    }

    ad_obj$fn(best_par)
    full_par <- if (!is.null(ad_obj$env$last.par.best)) ad_obj$env$last.par.best else ad_obj$env$last.par

    unc_est_list <- BayesRTMB:::unconstrained_vector_to_list(full_par, rhs_mod$par_list)
    con_est_list <- BayesRTMB:::to_constrained(unc_est_list, rhs_mod$par_list)
    if (!is.null(rhs_mod$transform)) {
      tran_res <- rhs_mod$transform(rhs_mod$data, con_est_list)
      con_est_list <- c(con_est_list, tran_res)
    }

    b_est <- as.numeric(con_est_list$b)
    if (length(b_est) == 0 || any(is.na(b_est))) b_est <- rep(0, K_tmp)

    r_init <- ifelse(abs(b_est) > mean(abs(b_est)), 0.9, 0.1)
    tau_init <- pmax(abs(b_est), 0.01)
    beta_raw_init <- b_est / (r_init * tau_init)

    init <- list(beta_raw = beta_raw_init, r = r_init, tau = tau_init)
    if (has_intercept && !is.null(con_est_list$Intercept_c)) {
      init$Intercept_c <- as.numeric(con_est_list$Intercept_c)[1]
    }
  } else if (is.null(init)) {
    tryCatch({
      fixed_formula <- if (requireNamespace("reformulas", quietly = TRUE)) reformulas::nobars(formula) else suppressWarnings(lme4::nobars(formula))
      glm_fam <- switch(family, "gaussian" = gaussian(), "student_t" = gaussian(), "lognormal" = gaussian(link="log"), "bernoulli" = binomial(), "binomial" = binomial(), "poisson" = poisson(), "neg_binomial" = poisson(), "gamma" = Gamma(link="log"), gaussian())
      init_fit <- suppressWarnings(glm(fixed_formula, data = data, family = glm_fam))
      init_coef <- unname(coef(init_fit))
      init_coef[is.na(init_coef)] <- 0

      init <- list()
      if (has_intercept) init$Intercept_c <- init_coef[1]

      if (regularization == "none" && K_tmp > 0) {
        if (has_intercept) init$b <- init_coef[-1]
        else init$b <- init_coef
      }
    }, error = function(e) init <- NULL)
  }

  dat <- list(Y = Y, trials = trials, X = X)
  if (has_random) {
    dat$Zt <- Zt
    dat$group_idx <- group_idx
  }
  if (!is.null(offset)) dat$offset <- offset
  if (family == "ordered") dat$num_categories <- length(unique(Y))

  # --- Setup AST ---
  setup_exprs <- list()
  setup_exprs[[1]] <- quote(N <- length(Y))
  setup_exprs[[2]] <- quote(K <- ncol(X))
  if (has_random) {
    setup_exprs[[3]] <- quote(num_groups <- max(group_idx))
    setup_exprs[[4]] <- quote(num_ranef <- nrow(Zt) / num_groups)
    setup_exprs[[5]] <- quote(Z_mat <- matrix(0, nrow = N, ncol = num_ranef))
    setup_exprs[[6]] <- quote(
      for (i in 1:N) {
        g <- group_idx[i]
        Z_mat[i, ] <- Zt[((g - 1) * num_ranef + 1):(g * num_ranef), i]
      }
    )
  }

  if (use_weak_info) {
    if (family %in% c("bernoulli", "binomial", "ordered")) {
      setup_exprs[[length(setup_exprs) + 1]] <- quote(base_scale <- pi / sqrt(3))
      setup_exprs[[length(setup_exprs) + 1]] <- quote(alpha_prior_sd <- base_scale * weak_info_prior$max_beta)
      setup_exprs[[length(setup_exprs) + 1]] <- quote(mid_y <- 0)
    } else if (family %in% c("poisson", "neg_binomial", "gamma")) {
      setup_exprs[[length(setup_exprs) + 1]] <- quote(base_scale <- 1.0)
      setup_exprs[[length(setup_exprs) + 1]] <- quote(alpha_prior_sd <- base_scale)
      setup_exprs[[length(setup_exprs) + 1]] <- quote(mid_y <- 0)
    } else {
      setup_exprs[[length(setup_exprs) + 1]] <- quote(half_d_y <- diff(y_range) / 2)
      #setup_exprs[[length(setup_exprs) + 1]] <- quote(if (half_d_y == 0) half_d_y <- 0.5)
      setup_exprs[[length(setup_exprs) + 1]] <- quote(base_scale <- half_d_y * weak_info_prior$sd_ratio)
      setup_exprs[[length(setup_exprs) + 1]] <- quote(alpha_prior_sd <- half_d_y)
      setup_exprs[[length(setup_exprs) + 1]] <- quote(mid_y <- mean(y_range))
      setup_exprs[[length(setup_exprs) + 1]] <- quote(sigma_rate <- 1.0 / base_scale)
    }

    setup_exprs[[length(setup_exprs) + 1]] <- quote(tau_rate <- 1.0 / base_scale)

    if (K_tmp > 0) {
      setup_exprs[[length(setup_exprs) + 1]] <- quote(X_mean <- apply(X, 2, mean))
      setup_exprs[[length(setup_exprs) + 1]] <- quote(X_sd <- apply(X, 2, sd))
      setup_exprs[[length(setup_exprs) + 1]] <- quote(beta_prior_sd <- weak_info_prior$max_beta * base_scale / X_sd)
      if (has_intercept) {
        setup_exprs[[length(setup_exprs) + 1]] <- quote(X_c <- X - rep(1, N) %*% t(X_mean))
      }

      if (regularization == "rhs") {
        setup_exprs[[length(setup_exprs) + 1]] <- quote(p0 <- min(weak_info_prior$expected_vars, K - 1))
        setup_exprs[[length(setup_exprs) + 1]] <- quote(if (p0 < 1) p0 <- 1)
        setup_exprs[[length(setup_exprs) + 1]] <- quote(tau0 <- (p0 / (K - p0)) * (base_scale / sqrt(N)))
        setup_exprs[[length(setup_exprs) + 1]] <- quote(half_slab_df <- weak_info_prior$slab_df / 2.0)
        setup_exprs[[length(setup_exprs) + 1]] <- quote(half_slab_scale2 <- (weak_info_prior$slab_df * weak_info_prior$slab_scale^2) / 2.0)
      } else if (regularization == "ssp") {
        setup_exprs[[length(setup_exprs) + 1]] <- quote(tau_scale <- base_scale / X_sd)
      }
    }
  } else {
    # 固定事前分布の場合の最低限の計算
    if (K_tmp > 0) {
      setup_exprs[[length(setup_exprs) + 1]] <- quote(X_mean <- apply(X, 2, mean))
      if (has_intercept) {
        setup_exprs[[length(setup_exprs) + 1]] <- quote(X_c <- X - rep(1, N) %*% t(X_mean))
      }
    }
  }
  setup_ast <- as.call(c(list(as.name("{")), setup_exprs))

  tmp_env <- list2env(dat)
  eval(setup_ast, tmp_env)
  N <- tmp_env$N; K <- tmp_env$K
  if (has_random) {
    num_groups <- tmp_env$num_groups; num_ranef <- tmp_env$num_ranef
  }

  # --- Parameters AST ---
  param_exprs <- list()
  if (has_intercept) param_exprs[[length(param_exprs) + 1]] <- quote(Intercept_c <- Dim(1))
  if (K > 0) {
    if (regularization == "none") {
      param_exprs[[length(param_exprs) + 1]] <- quote(b <- Dim(K))
    } else if (regularization == "rhs") {
      param_exprs[[length(param_exprs) + 1]] <- quote(z <- Dim(K))
      param_exprs[[length(param_exprs) + 1]] <- quote(lambda <- Dim(K, lower = 0))
      param_exprs[[length(param_exprs) + 1]] <- quote(w_lambda <- Dim(K, lower = 0))
      param_exprs[[length(param_exprs) + 1]] <- quote(tau_hs <- Dim(1, lower = 0))
      param_exprs[[length(param_exprs) + 1]] <- quote(w_tau <- Dim(1, lower = 0))
      param_exprs[[length(param_exprs) + 1]] <- quote(c2 <- Dim(1, lower = 0))
    } else if (regularization == "ssp") {
      param_exprs[[length(param_exprs) + 1]] <- quote(beta_raw <- Dim(K))
      param_exprs[[length(param_exprs) + 1]] <- quote(r <- Dim(K, lower = 0.001, upper = 0.999))
      param_exprs[[length(param_exprs) + 1]] <- quote(tau <- Dim(K, lower = 0))
    }
  }

  if (has_random) {
    if (num_ranef == 1) {
      param_exprs[[length(param_exprs) + 1]] <- quote(sd <- Dim(num_ranef, lower = 0))
      param_exprs[[length(param_exprs) + 1]] <- quote(r_re <- Dim(num_groups, random = TRUE))
    } else {
      param_exprs[[length(param_exprs) + 1]] <- quote(sd <- Dim(num_ranef, lower = 0))
      param_exprs[[length(param_exprs) + 1]] <- quote(CF_cor <- Dim(c(num_ranef, num_ranef), type = "CF_corr"))
      param_exprs[[length(param_exprs) + 1]] <- quote(r_re <- Dim(c(num_groups, num_ranef), random = TRUE))
    }
  }

  if (family %in% c("gaussian", "lognormal", "student_t")) param_exprs[[length(param_exprs) + 1]] <- quote(sigma <- Dim(1, lower = 0))
  if (family == "student_t") param_exprs[[length(param_exprs) + 1]] <- quote(nu <- Dim(1, lower = 2))
  if (family == "gamma") param_exprs[[length(param_exprs) + 1]] <- quote(shape <- Dim(1, lower = 0))
  if (family == "neg_binomial") param_exprs[[length(param_exprs) + 1]] <- quote(phi <- Dim(1, lower = 0))
  if (family == "ordered") param_exprs[[length(param_exprs) + 1]] <- quote(cutpoints <- Dim(num_categories - 1, type = "ordered"))
  param_ast <- as.call(c(list(as.name("{")), param_exprs))

  # --- Transform AST ---
  tran_exprs <- list()
  if (K > 0) {
    if (regularization == "rhs") {
      tran_exprs[[length(tran_exprs) + 1]] <- quote(lambda_sq <- lambda^2)
      tran_exprs[[length(tran_exprs) + 1]] <- quote(tau_sq <- tau_hs^2)
      tran_exprs[[length(tran_exprs) + 1]] <- quote(lambda_tilde <- sqrt((c2 * lambda_sq) / (c2 + tau_sq * lambda_sq)))
      tran_exprs[[length(tran_exprs) + 1]] <- quote(b <- z * lambda_tilde * tau_hs)
    } else if (regularization == "ssp") {
      tran_exprs[[length(tran_exprs) + 1]] <- quote(b <- beta_raw * r * tau)
    }
  }
  if (has_intercept) {
    if (K > 0) tran_exprs[[length(tran_exprs) + 1]] <- quote(Intercept <- Intercept_c - sum(X_mean * b))
    else tran_exprs[[length(tran_exprs) + 1]] <- quote(Intercept <- Intercept_c)
  }
  if (has_random && num_ranef > 1) tran_exprs[[length(tran_exprs) + 1]] <- quote(cor <- CF_cor %*% t(CF_cor))
  tran_ast <- if (length(tran_exprs) > 0) as.call(c(list(as.name("{")), tran_exprs)) else NULL

  # --- Model AST ---
  transform_exprs <- list()
  if (has_intercept) {
    if (K > 0) transform_exprs[[length(transform_exprs) + 1]] <- quote(eta <- as.vector(Intercept_c + X_c %*% b))
    else transform_exprs[[length(transform_exprs) + 1]] <- quote(eta <- rep(Intercept_c, N))
  } else {
    if (K > 0) transform_exprs[[length(transform_exprs) + 1]] <- quote(eta <- as.vector(X %*% b))
    else transform_exprs[[length(transform_exprs) + 1]] <- quote(eta <- rep(0, N))
  }
  if (has_random) {
    if (num_ranef > 1) {
      transform_exprs[[length(transform_exprs) + 1]] <- quote(for (i in 1:N) eta[i] <- eta[i] + sum(Z_mat[i, ] * r_re[group_idx[i], ] * sd))
    } else {
      transform_exprs[[length(transform_exprs) + 1]] <- quote(eta <- eta + Z_mat[,1] * r_re[group_idx] * sd)
    }
  }
  if (!is.null(offset)) transform_exprs[[length(transform_exprs) + 1]] <- quote(eta <- eta + offset)

  ll_data_exprs <- list()
  ll_data_exprs[[1]] <- switch(family,
                               "gaussian" = quote(Y ~ normal(eta, sigma)),
                               "lognormal" = quote(Y ~ lognormal(eta, sigma)),
                               "student_t" = quote(Y ~ student_t(nu, eta, sigma)),
                               "gamma" = quote(Y ~ gamma(shape, shape / exp(eta))),
                               "bernoulli" = quote(Y ~ bernoulli_logit(eta)),
                               "binomial" = quote(Y ~ binomial_logit(trials, eta)),
                               "poisson" = quote(Y ~ poisson(exp(eta))),
                               "neg_binomial" = quote(Y ~ neg_binomial_2(exp(eta), phi)),
                               "ordered" = quote(Y ~ ordered_logistic(eta, cutpoints))
  )

  ll_random_exprs <- list()
  if (has_random) {
    if (num_ranef > 1) {
      ll_random_exprs[[length(ll_random_exprs) + 1]] <- bquote(CF_cor ~ lkj_CF_corr(.(prior$lkj_eta)))
      ll_random_exprs[[length(ll_random_exprs) + 1]] <- quote(for (j in 1:num_groups) r_re[j, ] ~ multi_normal_CF(rep(0, num_ranef), rep(1, num_ranef), CF_cor))
    } else {
      ll_random_exprs[[length(ll_random_exprs) + 1]] <- quote(r_re ~ normal(0, 1))
    }
  }

  prior_exprs <- list()
  if (family %in% c("gaussian", "lognormal", "student_t")) {
    if (use_weak_info) {
      prior_exprs[[length(prior_exprs) + 1]] <- quote(sigma ~ exponential(sigma_rate))
    } else {
      prior_exprs[[length(prior_exprs) + 1]] <- bquote(sigma ~ exponential(.(prior$sigma_rate)))
    }
  }

  if (family == "student_t") prior_exprs[[length(prior_exprs) + 1]] <- bquote(nu ~ exponential(.(prior$nu_rate)))
  if (family == "gamma") prior_exprs[[length(prior_exprs) + 1]] <- bquote(shape ~ exponential(.(prior$shape_rate)))
  if (family == "neg_binomial") prior_exprs[[length(prior_exprs) + 1]] <- bquote(phi ~ exponential(.(prior$phi_rate)))
  if (family == "ordered") prior_exprs[[length(prior_exprs) + 1]] <- bquote(cutpoints ~ normal(0, .(prior$cutpoint_sd)))

  if (has_intercept) {
    if (use_weak_info) {
      prior_exprs[[length(prior_exprs) + 1]] <- quote(Intercept_c ~ normal(mid_y, alpha_prior_sd))
    } else {
      prior_exprs[[length(prior_exprs) + 1]] <- bquote(Intercept_c ~ normal(0, .(prior$Intercept_sd)))
    }
  }

  if (K > 0) {
    if (regularization == "none") {
      if (use_weak_info) {
        prior_exprs[[length(prior_exprs) + 1]] <- quote(b ~ normal(0, beta_prior_sd))
      } else {
        prior_exprs[[length(prior_exprs) + 1]] <- bquote(b ~ normal(0, .(prior$b_sd)))
      }
    } else if (regularization == "rhs") {
      prior_exprs[[length(prior_exprs) + 1]] <- quote(z ~ normal(0, 1))
      prior_exprs[[length(prior_exprs) + 1]] <- quote(w_lambda ~ gamma(0.5, 0.5))
      prior_exprs[[length(prior_exprs) + 1]] <- quote(lambda ~ half_normal(1 / sqrt(w_lambda)))
      prior_exprs[[length(prior_exprs) + 1]] <- quote(w_tau ~ gamma(0.5, 0.5))
      prior_exprs[[length(prior_exprs) + 1]] <- quote(tau_hs ~ half_normal(tau0 / sqrt(w_tau)))
      prior_exprs[[length(prior_exprs) + 1]] <- quote(c2 ~ inverse_gamma(half_slab_df, half_slab_scale2))
    } else if (regularization == "ssp") {
      prior_exprs[[length(prior_exprs) + 1]] <- quote(beta_raw ~ laplace(0, 0.5))
      prior_exprs[[length(prior_exprs) + 1]] <- bquote(mu_r <- log(.(weak_info_prior$ssp_ratio) / (1 - .(weak_info_prior$ssp_ratio))))
      prior_exprs[[length(prior_exprs) + 1]] <- quote(r ~ logit_normal(mu_r, 3))
      prior_exprs[[length(prior_exprs) + 1]] <- quote(tau ~ exponential(1 / tau_scale))
    }
  }

  if (has_random) {
    if (use_weak_info) {
      prior_exprs[[length(prior_exprs) + 1]] <- quote(sd ~ exponential(tau_rate))
    } else {
      prior_exprs[[length(prior_exprs) + 1]] <- bquote(sd ~ exponential(.(prior$sd_rate)))
    }
  }

  model_exprs <- list()
  model_exprs[[length(model_exprs) + 1]] <- "# Transform"
  model_exprs <- c(model_exprs, transform_exprs)
  model_exprs[[length(model_exprs) + 1]] <- "# Likelihood (Data)"
  model_exprs <- c(model_exprs, ll_data_exprs)
  if (has_random) {
    model_exprs[[length(model_exprs) + 1]] <- "# Likelihood (Random)"
    model_exprs <- c(model_exprs, ll_random_exprs)
  }
  model_exprs[[length(model_exprs) + 1]] <- "# Priors"
  model_exprs <- c(model_exprs, prior_exprs)

  model_ast <- as.call(c(list(as.name("{")), model_exprs))

  code_obj <- list(setup = setup_ast, parameters = param_ast)
  if (!is.null(tran_ast)) code_obj$transform <- tran_ast
  code_obj$model <- model_ast

  par_names_list <- list()
  if (K > 0) {
    par_names_list$b <- fixed_names
    if (regularization == "rhs") {
      par_names_list$z <- fixed_names; par_names_list$lambda <- fixed_names; par_names_list$w_lambda <- fixed_names
    } else if (regularization == "ssp") {
      par_names_list$beta_raw <- fixed_names; par_names_list$r <- fixed_names; par_names_list$tau <- fixed_names
    }
  }
  if (has_random) {
    par_names_list$sd <- ranef_names
    if (num_ranef > 1) par_names_list$cor <- ranef_names
  }

  view_vars <- c()
  if (has_intercept) view_vars <- c("Intercept")
  if (K > 0) view_vars <- c(view_vars, "b")
  view_vars <- c(view_vars, "sigma")
  if (has_random) {
    view_vars <- c(view_vars, "sd", "cor")
  }

  ordered_data <- env_to_ordered_list(tmp_env, dat, setup_ast)
  obj <- rtmb_model(data = ordered_data, code = code_obj, par_names = par_names_list, init = init, view = view_vars)
  obj$formula <- formula
  obj$raw_data <- data
  obj$family <- family

  return(obj)
}

#' RTMB-based GLM wrapper function (no random effects)
#'
#' @param formula Formula
#' @param data Data frame
#' @param family Character string of the distribution family (e.g., "gaussian", "binomial", "poisson")
#' @param penalty Type of regularization for fixed effects: "none", "rhs" (Regularized Horseshoe), or "ssp" (Spike and Slab Prior). Default is "none".
#' @param y_range Theoretical minimum and maximum values of the response variable as a vector c(min, max). Specifying this automatically enables weakly informative priors.
#' @param use_weak_info Logical; whether to explicitly use weakly informative priors (requires y_range for continuous models).
#' @param prior List of hyperparameters for the default fixed priors.
#' @param weak_info_prior List of hyperparameters for the weakly informative priors and regularization.
#' @param init List of initial values
#' @export
rtmb_glm <- function(formula, data, family = "gaussian",
                     penalty = c("none", "rhs", "ssp"),
                     y_range = NULL,
                     use_weak_info = FALSE,
                     prior = list(Intercept_sd = 10, b_sd = 10, sigma_rate = 5, sd_rate = 5, nu_rate = 0.1, cutpoint_sd = 2.5, shape_rate = 1.0, phi_rate = 1.0, lkj_eta = 1.0),
                     weak_info_prior = list(max_beta = 1, sd_ratio = 0.5, expected_vars = 3, slab_scale = 2.0, slab_df = 4.0, ssp_ratio = 0.25),
                     init = NULL) {
  regularization <- match.arg(penalty)
  rtmb_glmer(
    formula = formula,
    data = data,
    family = family,
    laplace = FALSE,
    penalty = regularization,
    y_range = y_range,
    use_weak_info = use_weak_info,
    prior = prior,
    weak_info_prior = weak_info_prior,
    init = init
  )
}

#' RTMB-based Linear Regression wrapper function
#'
#' @param formula Formula (e.g., Y ~ X1 + X2)
#' @param data Data frame
#' @param penalty Type of regularization for fixed effects: "none", "rhs" (Regularized Horseshoe), or "ssp" (Spike and Slab Prior). Default is "none".
#' @param y_range Theoretical minimum and maximum values of the response variable as a vector c(min, max). Specifying this automatically enables weakly informative priors.
#' @param use_weak_info Logical; whether to explicitly use weakly informative priors.
#' @param prior List of hyperparameters for the default fixed priors.
#' @param weak_info_prior List of hyperparameters for the weakly informative priors and regularization.
#' @param init List of initial values.
#' @export
rtmb_lm <- function(formula, data,
                    penalty = c("none", "rhs", "ssp"),
                    y_range = NULL,
                    use_weak_info = FALSE,
                    prior = list(Intercept_sd = 10, b_sd = 10, sigma_rate = 5, sd_rate = 5, nu_rate = 0.1, cutpoint_sd = 2.5, shape_rate = 1.0, phi_rate = 1.0),
                    weak_info_prior = list(max_beta = 1, sd_ratio = 0.5, expected_vars = 3, slab_scale = 2.0, slab_df = 4.0, ssp_ratio = 0.25),
                    init = NULL) {

  regularization <- match.arg(penalty)
  rtmb_glm(
    formula = formula,
    data = data,
    family = "gaussian",
    y_range = y_range,
    use_weak_info = use_weak_info,
    penalty = regularization,
    prior = prior,
    weak_info_prior = weak_info_prior,
    init = init
  )
}



#' RTMB-based Factor Analysis Wrapper
#'
#' @description
#' Performs exploratory factor analysis (EFA) using RTMB. It supports standard
#' rotation methods (e.g., varimax, promax) as well as regularized factor analysis
#' using a Spike-and-Slab Prior (SSP) for estimating sparse loading matrices.
#'
#' @param data Observation data frame or matrix (N x J).
#' @param nfactors Number of factors (K).
#' @param rotate String specifying the rotation method (e.g., "varimax", "promax", "ssp"). If NULL, no rotation is applied. Specifying "ssp" performs regularized factor analysis.
#' @param score Logical; if TRUE, factor scores are calculated in the generate block (default is FALSE).
#' @param prior List of hyperparameters for prior distributions. `ssp_ratio` represents the proportion of non-zero loadings per factor when "ssp" is specified.
#' @param init List of initial values. If not provided, initial values are automatically generated based on PCA or the psych package.
#' @export
rtmb_fa <- function(data, nfactors = 1, rotate = NULL, score = FALSE,
                    prior = list(mean_sd = 10, loadings_sd = 1, sd_rate = 10, ssp_ratio = 0.25),
                    init = NULL) {

  Y <- as.matrix(data)
  K <- nfactors

  default_prior <- list(mean_sd = 10, loadings_sd = 1, sd_rate = 10, ssp_ratio = 0.25)
  if (!is.null(prior)) {
    prior <- modifyList(default_prior, prior)
  } else {
    prior <- default_prior
  }

  var_names <- colnames(data)
  if (is.null(var_names)) var_names <- paste0("V", 1:ncol(Y))

  if (K >= ncol(Y)) stop("因子の数(K)は観測変数の数(J)より小さくする必要があります。")

  # SSPモデルかどうかの判定
  is_ssp <- !is.null(rotate) && rotate == "ssp"

  # 共通の setup ブロック
  setup_ast <- quote({
    N <- nrow(Y)
    J <- ncol(Y)
    Y_bar <- apply(Y, 2, mean)
    S_Y <- cov(Y) * (N - 1)
  })

  if (is_ssp) {
    if (is.null(prior$ssp_ratio)) prior$ssp_ratio <- 0.25

    dat_fa <- list(
      Y = Y, K_factors = K,
      prior_mean_sd = prior$mean_sd, prior_sd_rate = prior$sd_rate,
      ssp_ratio = prior$ssp_ratio
    )

    tmp_env <- list2env(dat_fa)
    eval(setup_ast, tmp_env)
    N <- tmp_env$N; J <- tmp_env$J; Y_bar <- tmp_env$Y_bar; S_Y <- tmp_env$S_Y

    if (score) dat_fa$Y <- Y

    # SSP用の初期値自動生成 (Base RのPCAとpromaxを利用)
    if (is.null(init)) {
      tryCatch({
        eig <- eigen(S_Y / (N - 1))
        L_pca <- eig$vectors[, 1:K, drop = FALSE] %*% diag(sqrt(eig$values[1:K]), nrow = K, ncol = K)
        var_Y <- diag(S_Y / (N - 1))

        if (K > 1) {
          pm <- stats::promax(L_pca, m = 4)
          init_Lambda <- unclass(pm$loadings)
          T_mat <- pm$rotmat
          Phi <- cov2cor(solve(t(T_mat) %*% T_mat))
          init_CF_Omega <- t(chol(Phi))
        } else {
          init_Lambda <- L_pca
          Phi <- matrix(1, nrow = 1, ncol = 1)
          init_CF_Omega <- matrix(1, nrow = 1, ncol = 1)
        }

        h2_raw <- rowSums(init_Lambda * (init_Lambda %*% Phi))
        init_sd <- sqrt(pmax(var_Y - h2_raw, 0.01 * var_Y))

        L_std <- init_Lambda / sqrt(var_Y)
        init_r <- ifelse(abs(L_std) > 0.2, 0.9, 0.1)

        init <- list(
          mean = Y_bar,
          Lambda_star = init_Lambda,
          sd = init_sd,
          CF_Omega = init_CF_Omega,
          r = init_r,
          tau = matrix(1.0, nrow = J, ncol = K)
        )
      }, error = function(e) {
        stop("初期値の自動生成に失敗しました。init 引数で手動で初期値を与えてください。詳細: ", conditionMessage(e))
      })
    }

    param_ast <- quote({
      mean = Dim(dim = J)
      Lambda_star = Dim(c(J, K_factors))
      r = Dim(c(J, K_factors), lower = 0.001, upper = 0.999)
      tau = Dim(c(J, K_factors), lower = 0)
      sd = Dim(J, lower = 0)
      CF_Omega = Dim(c(K_factors, K_factors), type = "CF_corr")
    })

    tran_ast <- quote({
      L_raw <- Lambda_star * r * tau
      h2 <- rowSums(L_raw * (L_raw %*% CF_Omega))
      var_Y <- h2 + sd^2
      sd_Y <- sqrt(var_Y)
      L <- L_raw / sd_Y
      fa_cor <- CF_Omega %*% t(CF_Omega)
    })

    model_ast <- quote({
      S_Y ~ sufficient_multi_normal_fa(N, Y_bar, mean, sd, L_raw %*% CF_Omega)
      mean ~ normal(0, prior_mean_sd)
      sd ~ exponential(prior_sd_rate)
      CF_Omega ~ lkj_CF_corr(1)

      mu_r <- log(ssp_ratio / (1 - ssp_ratio))
      r ~ logit_normal(mu_r, 3)
      tau ~ exponential(1)
      Lambda_star ~ laplace(0, 1)
    })

    base_gq <- quote({
      Sigma <- L_raw %*% fa_cor %*% t(L_raw) + diag(sd^2)
      var_total <- diag(Sigma)
      var_common <- rowSums(L_raw * (L_raw %*% CF_Omega))
      communality <- var_common / var_total
      out <- list(communality = communality)
    })

    score_expr <- if (score) {
      quote({
        Y_c <- matrix(0, nrow = N, ncol = J)
        for (i in 1:N) Y_c[i, ] <- Y[i, ] - mean
        out$score <- Y_c %*% solve(Sigma, L_raw %*% fa_cor)
      })
    } else quote({})

    ret_expr <- quote({ return(out) })
    gq_ast <- as.call(c(list(as.name("{")), as.list(base_gq)[-1], as.list(score_expr)[-1], as.list(ret_expr)[-1]))

    code_args <- list(setup = setup_ast, parameters = param_ast, transform = tran_ast, model = model_ast, generate = gq_ast)
    code_obj <- eval(as.call(c(list(as.name("rtmb_code")), code_args)))

    p_names <- list(
      mean = var_names,
      Lambda_star = var_names,
      r = var_names,
      tau = var_names,
      sd = var_names,
      CF_Omega = paste0("Factor", 1:K),
      L_raw = var_names,
      L = var_names,
      fa_cor = paste0("Factor", 1:K),
      communality = var_names
    )
    if (score) {
      ind_names <- rownames(data)
      if (is.null(ind_names)) ind_names <- paste0("Id", 1:N)
      p_names[["score"]] <- list(ind_names, paste0("Factor", 1:K))
    }

    target_view <- c("L", "sd", "fa_cor")

    obj <- rtmb_model(
      data = dat_fa,
      code = code_obj,
      par_names = p_names,
      init = init,
      view = target_view
    )

    return(obj)

  } else {
    # --- 既存の回転ロジック (varimax, promax 等) ---
    dat_fa <- list(
      Y = Y, K_factors = K,
      prior_mean_sd = prior$mean_sd, prior_loadings_sd = prior$loadings_sd, prior_sd_rate = prior$sd_rate
    )

    tmp_env <- list2env(dat_fa)
    eval(setup_ast, tmp_env)
    N <- tmp_env$N; J <- tmp_env$J; Y_bar <- tmp_env$Y_bar; S_Y <- tmp_env$S_Y

    if (score) dat_fa$Y <- Y

    if (is.null(init)) {
      tryCatch({
        eig <- eigen(S_Y / (N - 1))
        L_pca <- eig$vectors[, 1:K, drop = FALSE] %*% diag(sqrt(eig$values[1:K]), nrow=K, ncol=K)
        L_top <- L_pca[1:K, , drop = FALSE]
        qr_res <- qr(t(L_top))
        Q_mat <- qr.Q(qr_res)
        init_loadings <- L_pca %*% Q_mat
        init_sd <- pmax(diag(S_Y / (N - 1)) - rowSums(init_loadings^2), 0.01)^0.5

        for (j in 1:J) {
          for (k in 1:K) {
            if (j < k) init_loadings[j, k] <- 0
          }
        }
        init <- list(mean = Y_bar, L_raw = init_loadings, sd = init_sd)
      }, error = function(e) { init <- NULL })
    }

    param_ast <- quote({
      mean <- Dim(dim = J)
      L_raw <- Dim(dim = c(J, K_factors), type = "lower_tri")
      sd <- Dim(dim = J, lower = 0)
    })

    tran_ast <- quote({
      h2 <- rowSums(L_raw^2)
      var_Y <- h2 + sd^2
      sd_Y <- sqrt(var_Y)
      L <- L_raw / sd_Y
    })

    model_ast <- quote({
      S_Y ~ sufficient_multi_normal_fa(N, Y_bar, mean, sd, L_raw)
      mean ~ normal(0, prior_mean_sd)
      sd ~ exponential(prior_sd_rate)
      L_raw ~ lower_tri_normal(0, prior_loadings_sd)
    })

    base_gq <- quote({
      Sigma <- L_raw %*% t(L_raw) + diag(sd^2)
      var_total <- diag(Sigma)
      var_common <- rowSums(L_raw^2)
      communality <- var_common / var_total
      out <- list(communality = communality)
    })

    if (!is.null(rotate)) {
      rot_loadings_name <- paste0("L_", rotate)

      if (exists(rotate, mode = "function")) {
        rot_fn <- match.fun(rotate)
        fn_call <- as.name(rotate)
      } else if (requireNamespace("GPArotation", quietly = TRUE) &&
                 exists(rotate, where = asNamespace("GPArotation"), mode = "function")) {
        rot_fn <- getFromNamespace(rotate, "GPArotation")
        fn_call <- call("::", as.name("GPArotation"), as.name(rotate))
      } else {
        stop("Rotation function not found: ", rotate)
      }

      dummy_L <- matrix(rnorm(J * K), J, K)
      test_rot <- rot_fn(dummy_L)

      is_matrix_rot <- is.matrix(test_rot)
      has_phi <- !is_matrix_rot && !is.null(test_rot$Phi)

      if (is_matrix_rot) {
        rot_expr <- bquote({
          rot_obj <- .(fn_call)(L)
          rot_mat <- unclass(rot_obj)
          out[[.(rot_loadings_name)]] <- rot_mat
        })
        score_expr <- if (score) quote({
          Y_c <- matrix(0, nrow = N, ncol = J)
          for (i in 1:N) Y_c[i, ] <- Y[i, ] - mean
          rot_raw <- unclass(.(fn_call)(L_raw))
          if (!is.matrix(rot_raw)) rot_raw <- unclass(rot_raw$loadings)
          out$score <- Y_c %*% solve(Sigma, rot_raw)
        }) else quote({})
      } else {
        if (has_phi) {
          rot_expr <- bquote({
            rot_obj <- .(fn_call)(L)
            rot_mat <- unclass(rot_obj$loadings)
            out$fa_cor <- rot_obj$Phi
            out[[.(rot_loadings_name)]] <- rot_mat
          })
          score_expr <- if (score) quote({
            Y_c <- matrix(0, nrow = N, ncol = J)
            for (i in 1:N) Y_c[i, ] <- Y[i, ] - mean
            rot_raw_obj <- .(fn_call)(L_raw)
            rot_raw_mat <- unclass(rot_raw_obj$loadings)
            out$score <- Y_c %*% solve(Sigma, rot_raw_mat %*% rot_raw_obj$Phi)
          }) else quote({})
        } else {
          rot_expr <- bquote({
            rot_obj <- .(fn_call)(L)
            rot_mat <- unclass(rot_obj$loadings)
            out[[.(rot_loadings_name)]] <- rot_mat
          })
          score_expr <- if (score) quote({
            Y_c <- matrix(0, nrow = N, ncol = J)
            for (i in 1:N) Y_c[i, ] <- Y[i, ] - mean
            rot_raw <- unclass(.(fn_call)(L_raw)$loadings)
            out$score <- Y_c %*% solve(Sigma, rot_raw)
          }) else quote({})
        }
      }
    } else {
      has_phi <- FALSE
      rot_expr <- quote({})
      score_expr <- if (score) {
        quote({
          Y_c <- matrix(0, nrow = N, ncol = J)
          for (i in 1:N) Y_c[i, ] <- Y[i, ] - mean
          out$score <- Y_c %*% solve(Sigma, L_raw)
        })
      } else quote({})
    }

    ret_expr <- quote({ return(out) })

    gq_ast <- as.call(c(list(as.name("{")), as.list(base_gq)[-1], as.list(rot_expr)[-1], as.list(score_expr)[-1], as.list(ret_expr)[-1]))

    code_args <- list(setup = setup_ast, parameters = param_ast, transform = tran_ast, model = model_ast, generate = gq_ast)
    code_obj <- eval(as.call(c(list(as.name("rtmb_code")), code_args)))

    p_names <- list(
      mean = var_names,
      L_raw = var_names,
      sd = var_names,
      L = var_names,
      communality = var_names
    )
    if (!is.null(rotate)) {
      p_names[[paste0("L_", rotate)]] <- var_names
      if (has_phi) p_names[["fa_cor"]] <- paste0("Factor", 1:K)
    }
    if (score) {
      ind_names <- rownames(data)
      if (is.null(ind_names)) ind_names <- paste0("Id", 1:N)
      p_names[["score"]] <- list(ind_names, paste0("Factor", 1:K))
    }

    target_view <- if (!is.null(rotate)) c(paste0("L_", rotate), "sd", "fa_cor") else c("L", "sd", "fa_cor")

    obj <- rtmb_model(
      data = dat_fa,
      code = code_obj,
      par_names = p_names,
      init = init,
      view = target_view
    )

    return(obj)
  }
}

#' RTMB-based IRT (Item Response Theory) Wrapper
#'
#' @description
#' Performs Item Response Theory modeling (1PL, 2PL, 3PL, and Graded Response Model) using RTMB.
#' Missing values (NA) in the data are automatically removed internally for efficient computation.
#'
#' @param data A data frame or matrix of item responses (N persons x J items).
#' @param model Character string for the model type: "1PL", "2PL", or "3PL".
#' @param type Character string for the data type: "binary" or "ordered".
#' @param prior List of hyperparameters for prior distributions.
#' @param init List of initial values.
#' @export
rtmb_irt <- function(data, model = c("2PL", "1PL", "3PL"), type = c("binary", "ordered"),
                     prior = list(a_log_mean = 0, a_log_sd = 0.5, b_mean = 0, b_sd = 2.5, c_alpha = 1, c_beta = 4, theta_sd = 1),
                     init = NULL) {

  model <- match.arg(model)
  type <- match.arg(type)

  if (model == "3PL" && type == "ordered") {
    stop("3PLモデルは 'binary' データのみをサポートしています。")
  }

  Y <- as.matrix(data)

  # 行名・列名の取得
  item_names <- colnames(Y)
  if (is.null(item_names)) item_names <- paste0("Item", 1:ncol(Y))
  person_names <- rownames(Y)
  if (is.null(person_names)) person_names <- paste0("Person", 1:nrow(Y))

  # NAを除外して縦持ち(Long format)に変換 (高速化・不要な計算グラフの削減)
  obs_data <- which(!is.na(Y), arr.ind = TRUE)
  person_idx <- as.integer(obs_data[, "row"])
  item_idx <- as.integer(obs_data[, "col"])
  Y_obs <- Y[obs_data]

  if (type == "ordered") {
    # 順序尺度はカテゴリが1始まりであることを想定（ordered_logisticの仕様）
    min_y <- min(Y_obs)
    if (min_y == 0) {
      Y_obs <- Y_obs + 1
      message("順序データの最小値が0であったため、内部で1から始まるインデックスに自動変換しました。")
    }
  }

  default_prior <- list(a_log_mean = 0, a_log_sd = 0.5, b_mean = 0, b_sd = 2.5, c_alpha = 1, c_beta = 4, theta_sd = 1)
  if (!is.null(prior)) prior <- modifyList(default_prior, prior) else prior <- default_prior

  # ラッパー関数側から事前処理を消し、生の行列 Y のみ渡す
  dat <- list(
    Y = Y,
    prior_a_log_mean = prior$a_log_mean,
    prior_a_log_sd = prior$a_log_sd,
    prior_b_mean = prior$b_mean,
    prior_b_sd = prior$b_sd,
    prior_c_alpha = prior$c_alpha,
    prior_c_beta = prior$c_beta,
    prior_theta_sd = prior$theta_sd
  )

  # --- Setup ブロックの構築 ---
  setup_exprs <- list()
  setup_exprs[[1]] <- quote(obs_data <- which(!is.na(Y), arr.ind = TRUE))
  setup_exprs[[2]] <- quote(person_idx <- as.integer(obs_data[, "row"]))
  setup_exprs[[3]] <- quote(item_idx <- as.integer(obs_data[, "col"]))
  setup_exprs[[4]] <- quote(Y_obs <- Y[obs_data])
  setup_exprs[[5]] <- quote(N_persons <- nrow(Y)) # もしくは max(person_idx)
  setup_exprs[[6]] <- quote(N_items <- ncol(Y))   # もしくは max(item_idx)
  setup_exprs[[7]] <- quote(N_obs <- length(Y_obs))

  if (type == "ordered") {
    # 順序尺度の0始まりを1始まりに補正する処理もsetup内で行う
    setup_exprs[[8]] <- quote(if (min(Y_obs) == 0) Y_obs <- Y_obs + 1)
    setup_exprs[[9]] <- quote(K_cat <- max(Y_obs))
  }

  setup_ast <- as.call(c(list(as.name("{")), setup_exprs))

  tmp_env <- list2env(dat)
  eval(setup_ast, tmp_env)

  # --- Parameters ブロックの構築 ---
  param_exprs <- list()
  param_exprs[[length(param_exprs) + 1]] <- quote(theta <- Dim(N_persons, random = TRUE))

  if (type == "binary") {
    param_exprs[[length(param_exprs) + 1]] <- quote(b <- Dim(N_items))
  } else {
    param_exprs[[length(param_exprs) + 1]] <- quote(b <- Dim(c(N_items, K_cat - 1), type = "ordered"))
  }

  if (model %in% c("2PL", "3PL")) {
    param_exprs[[length(param_exprs) + 1]] <- quote(a <- Dim(N_items, lower = 0))
  }
  if (model == "3PL") {
    param_exprs[[length(param_exprs) + 1]] <- quote(c <- Dim(N_items, lower = 0, upper = 1))
  }
  param_ast <- as.call(c(list(as.name("{")), param_exprs))

  # --- Model ブロックの構築 ---
  loop_body <- list()
  loop_body[[1]] <- quote(p <- person_idx[i])
  loop_body[[2]] <- quote(j <- item_idx[i])
  loop_body[[3]] <- quote(y <- Y_obs[i])

  if (type == "binary") {
    if (model == "1PL") {
      loop_body[[4]] <- quote(eta <- theta[p] - b[j])
    } else {
      loop_body[[4]] <- quote(eta <- a[j] * (theta[p] - b[j]))
    }

    if (model == "3PL") {
      loop_body[[5]] <- quote(prob <- c[j] + (1 - c[j]) * plogis(eta))
      loop_body[[6]] <- quote(y ~ bernoulli(prob))
    } else {
      loop_body[[5]] <- quote(y ~ bernoulli_logit(eta))
    }
  } else if (type == "ordered") {
    if (model == "1PL") {
      loop_body[[4]] <- quote(eta <- theta[p])
    } else {
      loop_body[[4]] <- quote(eta <- a[j] * theta[p])
    }
    loop_body[[5]] <- quote(y ~ ordered_logistic(eta, b[j, ]))
  }

  # ループ全体を構築
  loop_ast <- quote(for (i in 1:N_obs) {})
  loop_ast[[4]] <- as.call(c(list(as.name("{")), loop_body))

  model_exprs <- list()
  model_exprs[[length(model_exprs) + 1]] <- "# Likelihood"
  model_exprs[[length(model_exprs) + 1]] <- loop_ast

  model_exprs[[length(model_exprs) + 1]] <- "# Priors"
  if (model %in% c("2PL", "3PL")) {
    model_exprs[[length(model_exprs) + 1]] <- quote(a ~ lognormal(prior_a_log_mean, prior_a_log_sd))
  }
  if (type == "binary") {
    model_exprs[[length(model_exprs) + 1]] <- quote(b ~ normal(prior_b_mean, prior_b_sd))
  } else {
    model_exprs[[length(model_exprs) + 1]] <- quote(for (j in 1:N_items) b[j, ] ~ normal(prior_b_mean, prior_b_sd))
  }
  if (model == "3PL") {
    model_exprs[[length(model_exprs) + 1]] <- quote(c ~ beta(prior_c_alpha, prior_c_beta))
  }
  model_exprs[[length(model_exprs) + 1]] <- quote(theta ~ normal(0, prior_theta_sd))

  model_ast <- as.call(c(list(as.name("{")), model_exprs))

  # --- パラメータ名のマッピング ---
  code_obj <- list(setup = setup_ast, parameters = param_ast, model = model_ast)

  par_names_list <- list()
  par_names_list$theta <- person_names
  if (type == "binary") {
    par_names_list$b <- item_names
  } else {
    par_names_list$b <- list(item_names, paste0("Threshold", 1:(tmp_env$K_cat - 1)))
  }
  if (model %in% c("2PL", "3PL")) par_names_list$a <- item_names
  if (model == "3PL") par_names_list$c <- item_names

  view_vars <- c()
  if (model %in% c("2PL", "3PL")) view_vars <- c(view_vars, "a")
  view_vars <- c(view_vars, "b")
  if (model == "3PL") view_vars <- c(view_vars, "c")

  # --- 初期値の自動設定 ---
  if (is.null(init)) {
    init <- list()
    if (type == "binary") {
      init$b <- rep(0, length(item_names))
    }
    if (model %in% c("2PL", "3PL")) init$a <- rep(1.0, length(item_names))
    if (model == "3PL") init$c <- rep(0.1, length(item_names))
  }

  obj <- rtmb_model(data = as.list(tmp_env), code = code_obj, par_names = par_names_list, init = init, view = view_vars)

  return(obj)
}


#' 相関行列 (多変量正規分布) 推定ラッパー
#'
#' @param data 観測データフレームまたは行列 (N x P)
#' @param prior 事前分布のハイパーパラメータのリスト
#' @export
rtmb_cor <- function(data, prior = list(lkj_eta = 1.0, mu_sd = 10, sigma_rate = 1.0)) {

  Y <- as.matrix(data)
  N <- nrow(Y)
  P <- ncol(Y)

  default_prior <- list(
    lkj_eta = 1.0,
    mu_sd = 10,
    sigma_rate = 1.0
  )
  if (!is.null(prior)) {
    prior <- modifyList(default_prior, prior)
  } else {
    prior <- default_prior
  }

  var_names <- colnames(data)
  if (is.null(var_names)) var_names <- paste0("V", 1:P)

  dat <- list(
    N = N, P = P, Y = Y,
    Y_bar = apply(Y, 2, mean), S_Y = cov(Y) * (N - 1),
    prior_lkj_eta = prior$lkj_eta, prior_sigma_rate = prior$sigma_rate, prior_mu_sd = prior$mu_sd
  )

  param_ast <- quote({
    mean   <- Dim(P)
    sd     <- Dim(P, lower = 0)
    CF_cor <- Dim(c(P, P), type = "CF_corr")
  })

  model_ast <- quote({
    mean ~ normal(0, prior_mu_sd)
    sd ~ exponential(prior_sigma_rate)
    CF_cor ~ lkj_CF_corr(prior_lkj_eta)
    S_Y ~ sufficient_multi_normal_CF(N, Y_bar, mean, sd, CF_cor)
  })

  tran_ast <- quote({
    cor <- CF_cor %*% t(CF_cor)
  })

  # --- 新しい rtmb_code への組み立て ---
  code_obj <- list(parameters = param_ast, model = model_ast, transform = tran_ast)

  obj <- rtmb_model(
    data = dat,
    code = code_obj,
    par_names = list(mean = var_names, sd = var_names, cor = var_names),
    view = c("cor")
  )

  return(obj)
}



